# Example: computing error budget status from SLO data
# Run before the meeting to populate the packet

from dataclasses import dataclass
from datetime import date
import calendar

@dataclass
class SLOStatus:
    slo_target: float           # e.g. 0.999 for 99.9%
    actual_availability: float  # e.g. 0.9982
    month: date

    @property
    def total_minutes(self) -> float:
        days = calendar.monthrange(self.month.year, self.month.month)[1]
        return days * 24 * 60

    @property
    def budget_minutes(self) -> float:
        """Total allowed downtime minutes for the month."""
        return self.total_minutes * (1 - self.slo_target)

    @property
    def consumed_minutes(self) -> float:
        """Actual downtime minutes consumed."""
        return self.total_minutes * (1 - self.actual_availability)

    @property
    def remaining_minutes(self) -> float:
        return self.budget_minutes - self.consumed_minutes

    @property
    def budget_percent_remaining(self) -> float:
        if self.budget_minutes == 0:
            return 0.0
        return max(0.0, self.remaining_minutes / self.budget_minutes * 100)

    def policy_status(self) -> str:
        """Return the error budget policy tier."""
        pct = self.budget_percent_remaining
        if pct >= 50:
            return "GREEN: full feature velocity allowed"
        elif pct >= 10:
            return "YELLOW: pause non-critical releases"
        elif pct > 0:
            return "ORANGE: freeze all non-emergency changes"
        else:
            return "RED: error budget exhausted — incident response mode"


# Example output for review packet
status = SLOStatus(
    slo_target=0.999,
    actual_availability=0.9982,
    month=date(2026, 6, 1)
)
print(f"SLO Target:          {status.slo_target*100:.3f}%")
print(f"Actual Availability: {status.actual_availability*100:.4f}%")
print(f"Budget (minutes):    {status.budget_minutes:.1f}")
print(f"Consumed (minutes):  {status.consumed_minutes:.1f}")
print(f"Remaining:           {status.remaining_minutes:.1f} min ({status.budget_percent_remaining:.1f}%)")
print(f"Policy:              {status.policy_status()}")

# SLO Target:          99.900%
# Actual Availability: 99.8200%
# Budget (minutes):    43.2
# Consumed (minutes):  51.8  <-- over budget
# Remaining:           -8.6 min (0.0%)
# Policy:              RED: error budget exhausted — incident response mode

import json
from pathlib import Path

THRESHOLD_PCT = 15.0  # flag if change exceeds this percentage

def load_metrics(month_dir: Path) -> dict:
    return json.loads((month_dir / "llm-metrics.json").read_text())

def compare_months(current: dict, prior: dict) -> list[dict]:
    """Return flagged metrics that changed more than THRESHOLD_PCT."""
    flags = []
    for key in current:
        if key not in prior or not isinstance(current[key], (int, float)):
            continue
        c, p = float(current[key]), float(prior[key])
        if p == 0:
            continue
        change_pct = (c - p) / p * 100
        if abs(change_pct) >= THRESHOLD_PCT:
            flags.append({
                "metric": key,
                "prior": p,
                "current": c,
                "change_pct": round(change_pct, 1),
                "direction": "up" if change_pct > 0 else "down"
            })
    return sorted(flags, key=lambda x: abs(x["change_pct"]), reverse=True)

# Usage
current_metrics = load_metrics(Path("reliability-reviews/2026-06"))
prior_metrics   = load_metrics(Path("reliability-reviews/2026-05"))

flags = compare_months(current_metrics, prior_metrics)
if flags:
    print("=== LLM METRIC ANOMALIES (>15% change) ===")
    for f in flags:
        arrow = "▲" if f["direction"] == "up" else "▼"
        print(f"  {arrow} {f['metric']}: {f['prior']:.2f} → {f['current']:.2f} ({f['change_pct']:+.1f}%)")
else:
    print("No significant LLM metric changes this month.")

